    ],
    "contract_compliance": "Logging contract is well-defined with request_id, order_id, from_state, to_state, actor_id, duration_ms, and error_code. However, no trace_id or correlation_id means logs cannot be joined across service boundaries.",
    "data_flow_integrity": "Critical gap: failed state transitions are lost. No event log, no outbox, no dead-letter queue. Once a transition fails, the only evidence is the log line and the metric increment. The order is stuck with no automated recovery path."
  },

  "observability_review": {
    "logging": {
      "coverage": "adequate",
      "gaps": [
        "No trace_id or span_id for cross-service correlation",
        "No log field indicating retry attempt number or whether the failure is transient vs permanent",
        "No log entry capturing the reason WHY the transition failed (e.g., precondition check, downstream timeout, DB constraint) — error_code alone may be insufficient at 3am"
      ]
    },
    "metrics": {
      "coverage": "Partial — transition counts and duration histograms exist, but critical operational metrics are missing",
      "gaps": [
        "No metric for orders currently stuck in a given state (gauge of orders_in_state{state=PROCESSING} with age bucketing)",
        "No metric for transition queue depth or processing lag",
        "No metric for error_code breakdown — the alert fires on all failures equally, making it impossible to distinguish a DB outage from a business rule violation without reading logs",
        "No metric for retry counts or exhausted retries",
        "No SLO-based burn rate alerting — the >5/min threshold is arbitrary and will either fire too late under gradual degradation or too early during a brief spike"
      ]
    },
    "tracing": {
      "coverage": "Missing entirely",
      "gaps": [
        "No distributed tracing — this is the single biggest incident response gap",
        "Cannot follow a single order's lifecycle across services",
        "Cannot determine if the state machine is the cause or the victim of failures"
      ]
    },
    "debugging_capability": "An on-call engineer can query logs by order_id to see what happened to a specific order, and can check Prometheus for failure rates. However, they CANNOT: (1) trace failures upstream to determine root cause across services, (2) determine the blast radius by querying how many orders are stuck, (3) replay failed transitions to recover, (4) distinguish transient from permanent failures without reading individual log lines. At 3am, this means the engineer is grep-ing logs manually while customers are stuck."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Orders stuck in PROCESSING state due to downstream service unavailability",
        "handling": "unhandled",
        "recommendation": "Implement an outbox pattern or event log so failed transitions can be replayed. Add a dead-letter mechanism for transitions that fail after max retries."
      },
      {
        "scenario": "Gradual increase in transition failures (e.g., slow DB degradation)",
        "handling": "partial",
        "recommendation": "The >5/min alert is a static threshold that misses slow-burn incidents. Implement burn-rate alerting against an SLO (e.g., 99.5% transition success over 1h rolling window)."
      },
      {
        "scenario": "Mass failure spike (e.g., DB goes down, all transitions fail simultaneously)",
        "handling": "partial",
        "recommendation": "Alert will fire, but the engineer has no automated remediation. No circuit breaker to stop hammering a failing dependency. No ability to batch-retry stuck orders after recovery."
      },
      {
        "scenario": "State machine processes a transition but crashes before emitting the event to downstream consumers",
        "handling": "unhandled",
        "recommendation": "Without transactional outbox, this creates a silent data inconsistency. Downstream systems believe the order is in state X while it is actually in state Y. Add transactional outbox or change-data-capture."
      },
      {
        "scenario": "On-call engineer needs to manually unstick orders after an incident",
        "handling": "unhandled",
        "recommendation": "No tooling exists for bulk state recovery. The engineer will need to write ad-hoc DB queries under pressure at 3am. Provide a CLI or admin API for safe manual state transitions with audit logging."
      }
    ],
    "retry_config": "Not described — no evidence of retry logic for failed transitions. Failed transitions appear to be fire-and-forget.",
    "timeout_config": "Not described — duration_ms is logged but no timeout enforcement is mentioned. Long-running transitions could silently hold resources.",
    "circuit_breakers": "None. If a downstream dependency fails, the state machine will continue attempting transitions and failing, generating noise and potentially exhausting resources.",
    "graceful_degradation": "None. There is no fallback behavior, no queue-and-retry, no ability to accept transitions and process them later. Failures are immediate and unrecoverable without manual intervention."
  },

  "operational_readiness": {
    "deployment_ready": false,
    "rollback_capable": false,
    "rollback_plan": "Not assessed — the focus here is incident response readiness, not deployment. However, the lack of an event log means that if a bad deployment causes incorrect state transitions, there is no way to identify and revert affected orders.",
    "monitoring_coverage": "Insufficient for incident response. The alert fires on failures, but the on-call engineer lacks the tools to diagnose root cause (no tracing), assess blast radius (no stuck-order gauge), or recover (no replay). The 18-month-old runbook is likely inaccurate and will mislead the engineer under pressure.",
    "on_call_documentation": "Runbook exists but is 18 months stale. This is a liability — stale runbooks are worse than no runbook because they give false confidence. The runbook likely references outdated service topology, old escalation contacts, and deprecated remediation steps.",
    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": ["Distributed tracing backend (Jaeger/Tempo) or integration with existing APM", "Dead-letter queue or event store for failed transition replay"],
      "new_queues_topics": ["Dead-letter queue for failed state transitions", "Optionally: transactional outbox topic for reliable downstream notification"],
      "config_changes": ["Add trace context propagation to service configuration", "Configure circuit breaker thresholds for downstream dependencies"],
      "infra_provisioning": ["Persistent storage for event log / outbox if replay capability is added"]
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": false,
      "large_table_impact": false,
      "details": "Not applicable to this review — assessing operational readiness of existing service, not a migration."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
      "type": "missing_observability",
      "issue": "No distributed tracing makes root cause analysis across service boundaries impossible during incidents",
      "reason": "The on-call engineer cannot determine whether the state machine is the cause or victim of failures. With only logs and coarse metrics, diagnosing cross-service issues requires manual log correlation across multiple systems — unacceptable during a live incident. This is the #1 gap to close.",
      "routed_to": "Coach K"
    },
    {
      "type": "missing_observability",
      "issue": "No stuck-order gauge metric — blast radius is unknowable without querying the database directly",
      "reason": "When paged, the first question is 'how many orders are affected?' Currently answering this requires a production DB query. A gauge metric like orders_in_state{state=PROCESSING, age_bucket='5m+'} would answer this instantly on a dashboard.",
      "routed_to": "Coach K"
    },
    {
      "type": "missing_observability",
      "issue": "No replay capability and no dead-letter mechanism for failed transitions — recovery is manual and error-prone",
      "reason": "After the root cause is fixed, there is no way to programmatically recover stuck orders. The on-call engineer must write ad-hoc queries or scripts under pressure. This extends incident duration and introduces risk of further data corruption.",
      "routed_to": "Coach K"
    },
    {
      "type": "missing_observability",
      "issue": "Runbook is 18 months stale — on-call documentation is a liability rather than an asset",
      "reason": "A stale runbook will actively mislead the on-call engineer. Must be updated to reflect current architecture, escalation paths, common failure modes, and step-by-step remediation procedures. Recommend coupling runbook freshness to a quarterly review cadence with ownership assigned.",
      "routed_to": "Coach K"
    }
  ],

  "confidence": {
    "level": 55,
